module RefModule(
	input clk,
	input rst,
	input ena,
	input [31:0] data_in,
	output reg [31:0] q);
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
		if (rst)
			q <= 32'b0;
		else if (ena)
			q <= data_in;
	end
endmodule
